            throw new IllegalArgumentException("Order has no items");
        }
        if (order.getCustomer() == null) {
            throw new IllegalArgumentException("Order has no customer");
        }
        if (order.getCustomer().getAddress() == null) {
            throw new IllegalArgumentException("Customer has no address");
        }

        // Calculate total
        double total = 0;
        for (OrderItem item : order.getItems()) {
            total += item.getPrice() * item.getQuantity();
        }

        // Apply discount
        double discount = 0;
        if (order.getCustomer().getType().equals("VIP")) {
            discount = total * 0.1;
        } else if (order.getCustomer().getType().equals("Premium")) {
            discount = total * 0.15;
        } else if (order.getCustomer().getType().equals("Gold")) {
            discount = total * 0.2;
        }

        // Save order
